-- Corrigir labels das fases existentes
-- round_of_32 (16 jogos) = Rodada de 32 (oitavas de final da Copa 2026 com 48 times)
UPDATE tournament_phases SET label = 'Rodada de 32', `key` = 'round_of_32', `order` = 13 WHERE tournamentId = 2 AND `key` = 'round_of_32';

-- round_of_16 (8 jogos) = Oitavas de Final
UPDATE tournament_phases SET label = 'Oitavas de Final', `key` = 'round_of_16', `order` = 14 WHERE tournamentId = 2 AND `key` = 'round_of_16';

-- Inserir fase Quartas de Final (quarter_finals, 4 jogos, order=15)
INSERT INTO tournament_phases (tournamentId, `key`, label, enabled, `order`, slots, isKnockout, updatedAt)
VALUES (2, 'quarter_finals', 'Quartas de Final', 1, 15, 4, 1, NOW());

-- Ajustar order das fases seguintes
UPDATE tournament_phases SET `order` = 16 WHERE tournamentId = 2 AND `key` = 'semifinals';
UPDATE tournament_phases SET `order` = 17 WHERE tournamentId = 2 AND `key` = 'third_place';
UPDATE tournament_phases SET `order` = 18 WHERE tournamentId = 2 AND `key` = 'final';

-- Corrigir labels dos jogos existentes
UPDATE games SET phase = 'Rodada de 32' WHERE tournamentId = 2 AND phase = 'Oitavas de Final';
UPDATE games SET phase = 'Oitavas de Final' WHERE tournamentId = 2 AND phase = 'Quartas de Final';
UPDATE games SET phase = 'Quartas de Final' WHERE tournamentId = 2 AND phase = 'Semifinais' AND id IN (
  SELECT id FROM (SELECT id FROM games WHERE tournamentId = 2 AND phase = 'Semifinais' ORDER BY id LIMIT 4) t
);

